1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Customer = { yearsWithMHPCO: number };
3	type QuoteInput = {
4	  customer: Customer;
5	  items: Item[];
6	  previousContracts: number;
7	};
8	
9	const PROCESSING_FEE = 5;
10	const NEWCOMER_PER_ITEM_SURCHARGE_RATE = 0.1;
11	
12	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	const basePremiumForItem = (item: Item): number =>
22	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
23	
24	const isNewcomer = (customer: Customer): boolean =>
25	  customer.yearsWithMHPCO === 0;
26	
27	const premiumForItem = (item: Item, customer: Customer): number => {
28	  const base = basePremiumForItem(item);
29	  const newcomerSurcharge = isNewcomer(customer) ? base * NEWCOMER_PER_ITEM_SURCHARGE_RATE : 0;
30	  return base + newcomerSurcharge;
31	};
32	
33	export const quote = (input: QuoteInput): { premium: number } => {
34	  const itemsTotal = input.items.reduce(
35	    (sum, item) => sum + premiumForItem(item, input.customer),
36	    0,
37	  );
38	  return { premium: Math.ceil(itemsTotal + PROCESSING_FEE) };
39	};
40	
41	export const claim = (_input: unknown): unknown => {
42	  return undefined;
43	};
